        let reason: String
        let similarityType: String
        let expectedGenres: [String]?
    }
}

// MARK: - Station Config Extension for Hashing

extension LLMStationConfig {
    /// Generate a stable hash for caching purposes
    var configHash: String {
        var components: [String] = []
        components.append("name:\(name)")
        components.append("desc:\(description)")
        components.append("prompt:\(originalPrompt)")

        if !suggestedGenres.isEmpty {
            components.append("genres:\(suggestedGenres.sorted().joined(separator: ","))")
        }
        if let decades = suggestedDecades, !decades.isEmpty {
            components.append("decades:\(decades.sorted().map { String($0) }.joined(separator: ","))")
        }
        if !moodKeywords.isEmpty {
            components.append("keywords:\(moodKeywords.sorted().joined(separator: ","))")
        }

        // Include ranges if set
        if let energy = energyRange {
            components.append("energy:\(energy.min)-\(energy.max)")
        }
        if let valence = valenceRange {
            components.append("valence:\(valence.min)-\(valence.max)")
        }

        let combined = components.joined(separator: "|")
        return combined.sha256Hash
    }
}

// MARK: - String SHA256 Extension

import CommonCrypto

extension String {
    /// Generate SHA256 hash of the string
    var sha256Hash: String {
        guard let data = self.data(using: .utf8) else { return self }
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}
